const cloud = require("wx-server-sdk");
cloud.init({ env: cloud.DYNAMIC_CURRENT_ENV });
const db = cloud.database();

exports.main = async (event, context) => {
  const wx = cloud.getWXContext();
  const userId = wx.OPENID;
  const orderNo = event && event.order_no ? String(event.order_no) : "";
  const adminMode = !!(event && event.admin_mode);

  console.log('[getOrder] start', new Date().toISOString(), { admin_mode: adminMode, has_order_no: !!orderNo });

  if (!orderNo) return { code: 1, msg: "ERR_INVALID_PARAMS" };

  // Admin mode: verify caller is admin, then query without user_id filter
  if (adminMode) {
    const adminRes = await db.collection("admin_users").where({ openid: userId }).limit(1).get();
    const adminUser = adminRes.data && adminRes.data.length ? adminRes.data[0] : null;
    const status = String((adminUser && adminUser.status) || "").toUpperCase();
    if (!adminUser || (status !== "ACTIVE" && status !== "ON" && status !== "1" && status !== "ENABLED")) {
      return { code: 1, msg: "ERR_ADMIN_FORBIDDEN" };
    }
  }

  const where = adminMode ? { order_no: orderNo } : { order_no: orderNo, user_id: userId };
  const res = await db.collection("orders").where(where).limit(1).get();
  if (!res.data || !res.data.length) return { code: 1, msg: "ERR_ORDER_NOT_FOUND" };
  const order = res.data[0];

  console.log('[getOrder] done', new Date().toISOString(), { admin_mode: adminMode, order_no: order.order_no });

  return {
    code: 0,
    msg: "ok",
    data: {
      order_no: order.order_no,
      user_id: adminMode ? (order.user_id || "") : undefined,
      status: order.status,
      items: order.items || [],
      address: order.address || null,
      total_amount: order.total_amount || 0,
      pay_amount: order.pay_amount,
      discount_amount: order.discount_amount || 0,
      points_used: order.points_used || 0,
      refund_status: order.refund_status || "NONE",
      refunded_amount: order.refunded_amount || 0,
      waybill_no: order.waybill_no || "",
      created_at: order.created_at,
      paid_at: order.paid_at || null,
      expire_at: order.expire_at || null,
      cancelled_at: order.cancelled_at || null
    }
  };
};
